gsap.registerPlugin(ScrollTrigger);

// Set negative margin for smooth entrance
gsap.set('.testimonial-section', {
  marginTop: '-100vh',
});

// Parallax text animation
const textTl = gsap.timeline({
  scrollTrigger: {
    trigger: '.testimonial-section',
    start: 'top bottom',
    end: 'bottom top',
    scrub: 1,
  },
});

textTl
  .to('.bg-text-1', { xPercent: 60 })
  .to('.bg-text-2', { xPercent: -30 }, '<')
  .to('.bg-text-3', { xPercent: 80 }, '<');

// Stack cards animation
const cardsTl = gsap.timeline({
  scrollTrigger: {
    trigger: '.testimonial-section',
    start: 'top top',
    end: '+=200%',
    scrub: 1,
    pin: true,
  },
});

cardsTl.from('.card', {
  yPercent: 100,
  stagger: 0.15,
  ease: 'power2.out',
});
